package com.tuowei.dazhongdianping.module.reservation.controller;import com.tuowei.dazhongdianping.common.api.*;import com.tuowei.dazhongdianping.module.reservation.model.request.*;import com.tuowei.dazhongdianping.module.reservation.service.ReservationService;import jakarta.validation.Valid;import java.time.LocalDate;import java.util.Map;import org.springframework.format.annotation.DateTimeFormat;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/c/v1") public class ReservationController{private final ReservationService service;public ReservationController(ReservationService service){this.service=service;}@GetMapping("/shops/{shopId}/reservation-slots")public ApiResponse<Map<String,Object>>slots(@PathVariable Long shopId,@RequestParam @DateTimeFormat(iso=DateTimeFormat.ISO.DATE)LocalDate date,@RequestParam Integer peopleCount){return ApiResponse.success(service.slots(shopId,date,peopleCount));}@PostMapping("/reservations")public ApiResponse<Map<String,Object>>create(@Valid @RequestBody ReservationCreateRequest r){return ApiResponse.success(service.create(r));}@GetMapping("/reservations")public ApiResponse<PageResult<Map<String,Object>>>list(@RequestParam(required=false)Integer status,@RequestParam(defaultValue="1")Integer page,@RequestParam(defaultValue="12")Integer pageSize){return ApiResponse.success(service.list(status,page,pageSize));}@GetMapping("/reservations/{id}")public ApiResponse<Map<String,Object>>detail(@PathVariable Long id){return ApiResponse.success(service.detail(id));}@PostMapping("/reservations/{id}/cancel")public ApiResponse<Map<String,Object>>cancel(@PathVariable Long id){return ApiResponse.success(service.cancel(id));}@PostMapping("/reservations/{id}/reschedule")public ApiResponse<Map<String,Object>>reschedule(@PathVariable Long id,@Valid @RequestBody ReservationRescheduleRequest r){return ApiResponse.success(service.reschedule(id,r));}}
